final:
module DFF_1bit(
   input                clk ,
   input                rst_n,
   input                D,

   output reg           Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 1'b0;
        else Q <= D;
    end
  always @(*) begin
    if (1'b0) begin
      Q <= ~D;
    end
  end

endmodule
